func isSectionHeading(line string) bool {
	if !strings.HasSuffix(line, ":") {
		return false
	}
	head := strings.TrimSuffix(line, ":")
	if head == "" {
		return false
	}
	for _, r := range head {
		switch {
		case r >= 'A' && r <= 'Z':
		case r >= '0' && r <= '9':
		case r == ' ', r == '_', r == '-', r == '/':
		default:
			return false
		}
	}
	return true
}

